import{_ as t,c as o,o as i,ag as a}from"./chunks/framework.DD2hp6gW.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"OptionBay","text":"Advanced Product Options & Custom Addons for WooCommerce.","tagline":"Empower your customers with unlimited product customization and live pricing updates.","image":{"src":"/logo-2.png","alt":"OptionBay Logo"},"actions":[{"theme":"brand","text":"Get Started","link":"/installation"},{"theme":"alt","text":"Create your first Option Group","link":"/option-groups"},{"theme":"alt","text":"Learn about Assignments","link":"/assignments"}]}},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1777110900000}'),r={name:"index.md"};function s(n,e,l,d,p,c){return i(),o("div",null,e[0]||(e[0]=[a('<h2 id="what-is-optionbay" tabindex="-1">What is OptionBay? <a class="header-anchor" href="#what-is-optionbay" aria-label="Permalink to &quot;What is OptionBay?&quot;">​</a></h2><p>Welcome to the official documentation for <strong>OptionBay</strong>!</p><p>OptionBay is a high-performance WooCommerce extension designed to help store owners offer complex product customizations without bloating their site. From simple text fields and quantity-based pricing to complex image swatches and conditional logic, OptionBay provides a unified, visual interface to build and manage product addons.</p><p>Whether you&#39;re selling custom-printed t-shirts, personalized gift boxes, or complex technical equipment, OptionBay gives you the tools to collect more data from your customers and increase your Average Order Value (AOV).</p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><p><strong>Visual Addon Builder:</strong></p><ul><li><strong>Drag-and-Drop Interface:</strong> Build complex forms in minutes using our intuitive React-based builder.</li><li><strong>Multiple Field Types:</strong> Supports Text, Number, Select, Radio, Checkbox, Image Swatches, Color Swatches, and more.</li><li><strong>Live Preview:</strong> See exactly how your options will look as you build them.</li></ul><p><strong>Dynamic Pricing Engine:</strong></p><ul><li><strong>Flexible Price Types:</strong> Add flat fees, percentage increases, or character-count pricing.</li><li><strong>Live Total Display:</strong> Shoppers see their total price update in real-time on the product page as they select options.</li><li><strong>WooCommerce Integration:</strong> Addon prices are automatically added to the cart total and displayed clearly in the order summary.</li></ul><p><strong>Rule-Based Assignments:</strong></p><ul><li><strong>Global &amp; Specific:</strong> Assign option groups to your entire store, specific categories, individual tags, or hand-picked products.</li><li><strong>Conditional Logic:</strong> Show or hide specific fields based on the values of other fields, creating a personalized shopping journey.</li></ul><p><strong>Optimized for Performance:</strong></p><ul><li><strong>Smart Code Splitting:</strong> Our modern architecture separates the management interface from the settings area to keep your WordPress admin fast.</li><li><strong>Native Experience:</strong> Integrated directly into the WooCommerce &#39;Products&#39; menu and settings tab for a seamless workflow.</li></ul><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><p>Ready to dive in? Here are the most important sections to get you started:</p><div class="vp-doc"><div class="vp-card-group"><div class="vp-card"><a href="./installation"><h3>1. Installation</h3><p>A step-by-step guide to installing the plugin and getting it ready for your store.</p></a></div><div class="vp-card"><a href="./option-groups"><h3>2. Option Groups</h3><p>Learn how to create reusable sets of options and addons for your products.</p></a></div><div class="vp-card"><a href="./assignments"><h3>3. Assignments</h3><p>Configure rules to display your options on specific products or categories.</p></a></div></div></div>',16)]))}const m=t(r,[["render",s]]);export{g as __pageData,m as default};
